import{C as i,o as t,c as l,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const d=JSON.parse('{"title":"6. Durable nonces","description":"","frontmatter":{},"headers":[],"relativePath":"module-3/6-durable-nonces.md","filePath":"module-3/6-durable-nonces.md","lastUpdated":1780937944000}'),r={name:"module-3/6-durable-nonces.md"},u=Object.assign(r,{setup(h){const n={id:"m3-6-nonces",title:"🧠 Mini-check: Durable nonces",intro:"2 питання.",questions:[{type:"explain",q:"Чому durable nonce замість recent blockhash для multisig workflows?",ideal:`Standard TX uses recent_blockhash (valid ~60 sec). Якщо TX takes > 60 sec collect signatures (multisig requires multiple signers у різних timezones) — blockhash expires, TX dies.

Durable nonce: special on-chain nonce account holds long-lived nonce value (updates тільки коли used). TX references цей nonce замість recent_blockhash. Не expires through time, тільки coли nonce account explicitly updated.

Workflow:
1. Create nonce account (one-time, rent reserve ~0.0015 SOL)
2. Get current nonce value: solana nonce <NONCE_ACCOUNT>
3. Build TX з durable nonce instead of recent_blockhash
4. Pass TX around team for multiple signatures (days/weeks OK)
5. Submit signed TX — landed, nonce advanced
6. Reuse nonce account для next operation

Downside: requires nonce account management. Most users don't need (regular TXs fine with recent_blockhash).`,explanation:"Module 3.6."},{type:"mcq",q:"Use cases для durable nonces?",options:["Multisig signing (collecting signatures over days)","Offline signing (cold wallet generates signed TX, brought online later)","Standard SOL transfer between two hot wallets","Scheduled TXs (signed now, submit later)"],correct:[0,1,3],explanation:"Standard transfers — use recent_blockhash. Nonces для long-lived/offline scenarios. Module 3.6."}]};return(p,s)=>{const e=i("Quiz");return t(),l("div",null,[s[0]||(s[0]=a(`<h1 id="_6-durable-nonces" tabindex="-1">6. Durable nonces <a class="header-anchor" href="#_6-durable-nonces" aria-label="Permalink to &quot;6. Durable nonces&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Durable nonce</strong> = alternative до recent_blockhash для TX expiry. Long-lived (не expires через time), enabling multisig signing flows, offline signing, scheduled transactions.</p><p>Standard recent_blockhash valid ~60 sec — insufficient для workflows requiring collecting multiple signatures over days.</p><h2 id="проблема-recent-blockhash" tabindex="-1">Проблема recent_blockhash <a class="header-anchor" href="#проблема-recent-blockhash" aria-label="Permalink to &quot;Проблема recent_blockhash&quot;">​</a></h2><p>З Module 3.1: TX needs <strong>recent blockhash</strong> for expiry tracking. Valid only ~150 slots (~60 sec). After expiry — TX rejected.</p><p>Adequate для:</p><ul><li>✅ Single-user TX submitted через wallet (instant signing + submit)</li><li>✅ DeFi swaps (signed і submitted у моментально)</li></ul><p>Insufficient для:</p><ul><li>❌ <strong>Multisig</strong>: 5 members у different timezones may take days to collect signatures</li><li>❌ <strong>Offline signing</strong>: cold wallet generates signed TX yesterday, online tomorrow</li><li>❌ <strong>Scheduled TXs</strong>: sign now, submit at specific future time</li></ul><h2 id="durable-nonce-mechanism" tabindex="-1">Durable nonce mechanism <a class="header-anchor" href="#durable-nonce-mechanism" aria-label="Permalink to &quot;Durable nonce mechanism&quot;">​</a></h2><p><strong>Nonce account</strong> = on-chain account з owner = System Program containing:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NonceAccount {</span></span>
<span class="line"><span>    state: Initialized,</span></span>
<span class="line"><span>    nonce: &lt;current nonce value, 32 bytes&gt;,</span></span>
<span class="line"><span>    authority: &lt;pubkey that може advance nonce&gt;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>TX references nonce account замість recent_blockhash:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TX {</span></span>
<span class="line"><span>    instructions: [</span></span>
<span class="line"><span>        // First instruction MUST be nonce advance:</span></span>
<span class="line"><span>        SystemProgram.advanceNonce(nonce_account, authority),</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        // Your actual operations follow:</span></span>
<span class="line"><span>        ...</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    recent_blockhash: &lt;nonce value&gt;,  // не real blockhash, durable nonce</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Validator checks: nonce value matches current nonce_account state → TX valid. After execution, nonce advances → can&#39;t replay TX.</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><h3 id="_1-create-nonce-account" tabindex="-1">1. Create nonce account <a class="header-anchor" href="#_1-create-nonce-account" aria-label="Permalink to &quot;1. Create nonce account&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-nonce-account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nonce-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.0015</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> authority-keypair.json</span></span></code></pre></div><p>Creates account з ~0.0015 SOL rent reserve. Authority defaults до funder.</p><h3 id="_2-query-current-nonce" tabindex="-1">2. Query current nonce <a class="header-anchor" href="#_2-query-current-nonce" aria-label="Permalink to &quot;2. Query current nonce&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nonce</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NONCE_ACCOUNT_PUBKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Output: &lt;32-byte hex nonce value&gt;</span></span></code></pre></div><h3 id="_3-build-tx-з-durable-nonce" tabindex="-1">3. Build TX з durable nonce <a class="header-anchor" href="#_3-build-tx-з-durable-nonce" aria-label="Permalink to &quot;3. Build TX з durable nonce&quot;">​</a></h3><p>Через SDK (CLI also supports). Example для transfer:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RECIPIENT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --nonce</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NONCE_ACCOUNT_PUBKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --nonce-authority</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nonce-authority-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --sign-only</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --blockhash</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">CURRENT_NONCE_VALU</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span></span></code></pre></div><p><code>--sign-only</code> produces signed TX <strong>без submitting</strong>. Can transfer signed TX bytes до next signer.</p><h3 id="_4-multi-signer-flow-multisig-pattern" tabindex="-1">4. Multi-signer flow (multisig pattern) <a class="header-anchor" href="#_4-multi-signer-flow-multisig-pattern" aria-label="Permalink to &quot;4. Multi-signer flow (multisig pattern)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Signer 1 (initial): create signed TX з durable nonce → send to Signer 2</span></span>
<span class="line"><span>Signer 2: add signature → send to Signer 3</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>Signer N (last): add signature → broadcast TX → nonce advances on chain</span></span></code></pre></div><p>Days/weeks elapsed = OK. Nonce only advances when TX submitted.</p><h3 id="_5-submit-signed-tx" tabindex="-1">5. Submit signed TX <a class="header-anchor" href="#_5-submit-signed-tx" aria-label="Permalink to &quot;5. Submit signed TX&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send-transaction</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --signed-transaction</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BASE64_T</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Або через wallet UI.</p><h3 id="_6-reuse-nonce-account" tabindex="-1">6. Reuse nonce account <a class="header-anchor" href="#_6-reuse-nonce-account" aria-label="Permalink to &quot;6. Reuse nonce account&quot;">​</a></h3><p>After successful execution, nonce automatically advanced. Query new nonce value, use for next operation:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NEW_NONCE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nonce</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NONCE_ACCOUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Build next TX з $NEW_NONCE</span></span></code></pre></div><p>One nonce account supports many sequential operations.</p><h2 id="authority-management" tabindex="-1">Authority management <a class="header-anchor" href="#authority-management" aria-label="Permalink to &quot;Authority management&quot;">​</a></h2><p><code>nonce-authority</code> controls nonce. Can:</p><ul><li>Advance nonce (auto-done by TX)</li><li>Withdraw funds from nonce account</li><li>Change authority до new key</li></ul><p>Authority changes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> authorize-nonce-account</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NONCE_ACCOUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    new-authority-keypair.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --nonce-authority</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> current-authority-keypair.json</span></span></code></pre></div><p>Withdraw:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> withdraw-from-nonce-account</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">NONCE_ACCOUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    recipient_pubkey</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    amount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --nonce-authority</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> authority-keypair.json</span></span></code></pre></div><h2 id="use-cases-для-lumlabs" tabindex="-1">Use cases для LumLabs <a class="header-anchor" href="#use-cases-для-lumlabs" aria-label="Permalink to &quot;Use cases для LumLabs&quot;">​</a></h2><ol><li><p><strong>Treasury multisig</strong> (Squads natively integrate з durable nonces):</p><ul><li>Сtake withdraw operations</li><li>Vote account authority changes</li><li>Treasury rebalancing</li></ul></li><li><p><strong>Withdrawer operations</strong>:</p><ul><li>Cold withdrawer signs durable-nonce TX</li><li>Submitted later через ops team</li><li>No real-time coordination needed</li></ul></li><li><p><strong>Scheduled operations</strong>:</p><ul><li>Sign now during business hours</li><li>Submit later through automation</li></ul></li></ol><h2 id="caveats" tabindex="-1">Caveats <a class="header-anchor" href="#caveats" aria-label="Permalink to &quot;Caveats&quot;">​</a></h2><ul><li>Adds complexity (nonce account management, advance instruction у TX)</li><li>Rent reserve locked у nonce account (~0.0015 SOL)</li><li>Authority key compromise = nonce account drainable</li><li>One nonce account = sequential operations (можеш мати кілька для parallel work)</li></ul><p>Most operators don&#39;t need this. Multisig orgs benefit most.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><p>Якщо LumLabs использовuw Squads (Module 8.7) — Squads handles durable nonces internally для long signing flows. Operator не interacts напряму.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,51)),o(e,{data:n}),s[1]||(s[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#d"><code>Durable nonce</code></a>, <a href="/glossary#n"><code>Nonce account</code></a>, <a href="/glossary#n"><code>Nonce authority</code></a>, <a href="/glossary#o"><code>Offline signing</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/implemented-proposals/durable-tx-nonces" target="_blank" rel="noreferrer">Anza: Durable Transaction Nonces</a></li><li><a href="https://solana.com/developers/cookbook/transactions/use-durable-nonce" target="_blank" rel="noreferrer">Solana Cookbook: Durable Nonce</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-3/5-versioned-tx-alts">← 5. Versioned TX &amp; ALTs</a></p>',6))])}}});export{d as __pageData,u as default};
